import { WorkshopData, EfficiencyCalculation } from "./types";

// NEW: Standardized Working Days for Strategic Planning
// Accounts for holidays, sick leave, and annual leave - separate from monthly reality
export function calculateStandardMonthlyDays(): number {
    // Default UK/Standard Values
    const daysInYear = 52 * 5; // 260 working days per year (5 days/week)
    const bankHolidays = 8; // Standard UK bank holidays
    const annualLeave = 25; // Standard annual leave allowance
    const sickDays = 4.4; // Average sick days per employee per year

    // Calculation: (260 - 37.4) / 12 = ~18.55 days
    const availableWorkingDays = daysInYear - bankHolidays - annualLeave - sickDays;
    const standardMonthlyDays = availableWorkingDays / 12;

    return standardMonthlyDays;
}

export function calculateEfficiency(data: WorkshopData): EfficiencyCalculation {
    // Calculate total expenses (Operational Costs)
    const fixedExpensesTotal = data.fixedExpenses.reduce((sum, exp) => sum + exp.value, 0)
    const marketingTotal = data.marketing.reduce((sum, exp) => sum + exp.value, 0)
    const loansTotal = data.loans.reduce((sum, loan) => sum + loan.monthlyRepayment, 0)
    const staffTotal = data.staff.reduce((sum, staff) => {
        const monthlySalary = staff.annualSalary / 12
        const pension = (monthlySalary * staff.pensionPercentage) / 100
        const tax = (monthlySalary * staff.employerTaxPercentage) / 100
        return sum + monthlySalary + pension + tax
    }, 0)
    const techniciansTotal = data.technicians.reduce((sum, tech) => {
        return sum + tech.hourlyPayRate * tech.billableHoursPerWeek * 4.33
    }, 0)

    // Separate Operational Costs from Owner Profit
    const totalOperationalExpenses = fixedExpensesTotal + marketingTotal + loansTotal + staffTotal + techniciansTotal
    const totalRevenueGoal = totalOperationalExpenses + data.ownerProfitGoal // Operational + Owner Profit

    // Get the Dynamic Average Working Days from monthlyWorkingDays array
    const totalAnnualDays = data.monthlyWorkingDays.reduce((sum, days) => sum + days, 0)
    const averageWorkingDays = totalAnnualDays / 12 // ✅ Dynamic average from user's monthly inputs

    const techCount = data.technicians.length || 0;
    const maxRevenue = (techCount * 8 * averageWorkingDays) * (data.avgLabourRate || 75);

    // Calculate Burdens
    const partsProfit = data.estimatedMonthlyPartsProfitEuro || 0
    const operationalBurden = totalOperationalExpenses - partsProfit // For Breakeven Efficiency
    const totalBurden = totalRevenueGoal - partsProfit // For Required Efficiency (includes owner profit)

    // A. Breakeven Efficiency Formula - Covers Operational Costs Only
    const breakevenEfficiency = maxRevenue > 0
        ? Math.round((operationalBurden / maxRevenue) * 100)
        : 0

    // B. Required Efficiency Formula - Covers Operational Costs + Owner Profit
    const requiredEfficiency = maxRevenue > 0
        ? Math.round((totalBurden / maxRevenue) * 100)
        : 0

    return {
        requiredEfficiency, // Higher - includes owner profit
        breakevenEfficiency, // Lower - operational costs only
        maxPotentialLaborRevenue: maxRevenue,
        totalTechHours: techCount * 8 * averageWorkingDays,
        laborBurden: totalBurden, // Total burden including owner profit
        breakevenBurden: operationalBurden // Operational burden only
    }
}

export function getEfficiencyColor(efficiency: number): "destructive" | "secondary" | "default" {
    if (efficiency > 100) return "destructive" // Impossible/Unrealistic
    if (efficiency > 85) return "secondary"   // High Stress (Amber)
    return "default" // Healthy (Green)
}

export function getEfficiencyLabel(efficiency: number): string {
    if (efficiency > 100) return "Impossible"
    if (efficiency > 85) return "High Stress"
    if (efficiency > 70) return "On Par"
    return "Healthy"
}
